<?php
class AppointmentController {
public static function store(): void { $u=$GLOBALS['auth_user']; $d=Request::json(); $db=Database::connection(); $p=$db->prepare('SELECT id FROM patients WHERE user_id=?');$p->execute([$u['id']]);$pid=$p->fetch()['id']; $q=$db->prepare('SELECT COUNT(*) c FROM appointments WHERE appointment_date=?');$q->execute([$d['appointment_date']]); $num='A-'.str_pad((string)($q->fetch()['c']+1),3,'0',STR_PAD_LEFT); $s=$db->prepare('INSERT INTO appointments (patient_id,service_name,appointment_date,appointment_time,complaint,queue_number,status,doctor_name,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,NOW(),NOW())'); $s->execute([$pid,$d['service_name'],$d['appointment_date'],$d['appointment_time'],$d['complaint']??null,$num,'pending',$d['doctor_name']??null]); Response::json(true,'Appointment berhasil dibuat',['id'=>$db->lastInsertId(),'queue_number'=>$num]); }
public static function me(): void { $u=$GLOBALS['auth_user']['id']; $s=Database::connection()->prepare('SELECT a.* FROM appointments a JOIN patients p ON p.id=a.patient_id WHERE p.user_id=? ORDER BY appointment_date DESC'); $s->execute([$u]); Response::json(true,'Data berhasil dimuat',$s->fetchAll()); }
public static function today(): void { $s=Database::connection()->prepare('SELECT * FROM appointments WHERE appointment_date=CURDATE() ORDER BY appointment_time ASC'); $s->execute(); Response::json(true,'Data berhasil dimuat',$s->fetchAll()); }
public static function updateStatus($id): void { $d=Request::json(); Database::connection()->prepare('UPDATE appointments SET status=?,updated_at=NOW() WHERE id=?')->execute([$d['status'],$id]); Response::json(true,'Status appointment diperbarui',(object)[]); }
}
